// Vanilla S07PacketRespawn definition (from all clients):
package net.minecraft.network.play.server;

public class S07PacketRespawn implements Packet<INetHandlerPlayClient> {
    private int dimensionID;
    private EnumDifficulty difficulty;
    private WorldSettings.GameType gameType;
    private WorldType worldType;

    public S07PacketRespawn() {}
    public S07PacketRespawn(int dimensionIDIn, EnumDifficulty difficultyIn,
                            WorldType worldTypeIn, WorldSettings.GameType gameTypeIn) {
        this.dimensionID = dimensionIDIn;
        this.difficulty = difficultyIn;
        this.gameType = gameTypeIn;
        this.worldType = worldTypeIn;
    }

    public void processPacket(INetHandlerPlayClient handler) {
        handler.handleRespawn(this);
    }

    public int getDimensionID() { return this.dimensionID; }
    public EnumDifficulty getDifficulty() { return this.difficulty; }
    public WorldSettings.GameType getGameType() { return this.gameType; }
    public WorldType getWorldType() { return this.worldType; }
}

// Vanilla NetHandlerPlayClient.handleRespawn():
public void handleRespawn(S07PacketRespawn packetIn) {
    if (packetIn.getDimensionID() != this.gameController.thePlayer.dimension) {
        // Dimension change — reset everything
        this.doneLoadingTerrain = false;
        this.gameController.loadWorld((WorldClient) null);
        this.gameController.theWorld = new WorldClient(
            this, new WorldSettings(...), packetIn.getDimensionID(),
            packetIn.getDifficulty(), this.gameController.mcProfiler);
        this.gameController.thePlayer.dimension = packetIn.getDimensionID();
        this.gameController.displayGuiScreen(new GuiDownloadTerrain(this));
    }
    this.gameController.thePlayer.setDead(false);
    this.gameController.thePlayer.setHealth(20.0F);
    // Re-sync keepalive
    this.netManager.sendPacket(new C00PacketKeepAlive(-1));
}

